mapper.insert:
WITH incoming(source,category,event_type,severity,database_name,user_name,object_name, query_id,sql_state,message,fingerprint,payload,sensitive_redacted,event_time) AS ( VALUES
(#{it.source},#{it.category},#{it.eventType},#{it.severity}, #{it.databaseName,jdbcType=VARCHAR},#{it.userName,jdbcType=VARCHAR},#{it.objectName,jdbcType=VARCHAR}, #{it.queryId,jdbcType=VARCHAR},#{it.sqlState,jdbcType=VARCHAR},#{it.message,jdbcType=VARCHAR}, #{it.fingerprint},CAST(#{it.payloadJson} AS jsonb),#{it.sensitiveRedacted}, to_timestamp(#{it.eventTimeMillis}/1000.0))
) INSERT INTO pg_operational_event (instance_id,source,category,event_type,severity,database_name,user_name,object_name, query_id,sql_state,message,fingerprint,payload,sensitive_redacted,event_time) SELECT #{instanceId},i.source,i.category,i.event_type,i.severity,i.database_name,i.user_name, i.object_name,i.query_id,i.sql_state,i.message,i.fingerprint,i.payload, i.sensitive_redacted,i.event_time FROM incoming i LEFT JOIN pg_operational_snapshot s ON s.instance_id=#{instanceId} AND s.fingerprint=i.fingerprint WHERE s.fingerprint IS NULL OR s.severity IS DISTINCT FROM i.severity
